-- =====================================================================-- 0015_policies.sql-- Policies por tabela. service_role bypassa RLS (sem policy explícita).-- anon: nenhuma policy = sem acesso.-- =====================================================================-- ============ TENANTS ============alter table public.tenants enable row level security;drop policy if exists tenants_select       on public.tenants;drop policy if exists tenants_update_owner on public.tenants;create policy tenants_select on public.tenants  for select to authenticated  using (id = app.current_tenant_id() and app.is_active_member());create policy tenants_update_owner on public.tenants  for update to authenticated  using (id = app.current_tenant_id() and app.is_owner())  with check (id = app.current_tenant_id() and app.is_owner());-- ============ TENANT_MEMBERSHIPS ============alter table public.tenant_memberships enable row level security;drop policy if exists memberships_select on public.tenant_memberships;drop policy if exists memberships_insert on public.tenant_memberships;drop policy if exists memberships_update on public.tenant_memberships;drop policy if exists memberships_delete on public.tenant_memberships;create policy memberships_select on public.tenant_memberships  for select to authenticated  using (    tenant_id = app.current_tenant_id()    and (      app.is_admin_or_owner()      or user_id in (select id from public.users where auth_user_id = auth.uid())    )  );create policy memberships_insert on public.tenant_memberships  for insert to authenticated  with check (    tenant_id = app.current_tenant_id()    and app.is_admin_or_owner()    and (role <> 'owner' or app.is_owner())  );create policy memberships_update on public.tenant_memberships  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy memberships_delete on public.tenant_memberships  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- ============ PEOPLE ============alter table public.people enable row level security;drop policy if exists people_select on public.people;drop policy if exists people_insert on public.people;drop policy if exists people_update on public.people;drop policy if exists people_delete on public.people;create policy people_select on public.people  for select to authenticated  using (    tenant_id = app.current_tenant_id()    and app.is_active_member()    and (      app.is_admin_or_owner()      or id = app.person_id_for_user()      or app.manages_person(id)    )  );create policy people_insert on public.people  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy people_update on public.people  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy people_delete on public.people  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- ============ TEMPLATES e configuração ============alter table public.templates                    enable row level security;alter table public.template_relationship_rules  enable row level security;alter table public.competencies                 enable row level security;alter table public.questionnaires               enable row level security;alter table public.questions                    enable row level security;alter table public.questionnaire_questions      enable row level security;-- templatesdrop policy if exists templates_select on public.templates;drop policy if exists templates_insert on public.templates;drop policy if exists templates_update on public.templates;drop policy if exists templates_delete on public.templates;create policy templates_select on public.templates  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy templates_insert on public.templates  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy templates_update on public.templates  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy templates_delete on public.templates  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- template_relationship_rulesdrop policy if exists trr_select on public.template_relationship_rules;drop policy if exists trr_insert on public.template_relationship_rules;drop policy if exists trr_update on public.template_relationship_rules;drop policy if exists trr_delete on public.template_relationship_rules;create policy trr_select on public.template_relationship_rules  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy trr_insert on public.template_relationship_rules  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy trr_update on public.template_relationship_rules  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy trr_delete on public.template_relationship_rules  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- competenciesdrop policy if exists competencies_select on public.competencies;drop policy if exists competencies_insert on public.competencies;drop policy if exists competencies_update on public.competencies;drop policy if exists competencies_delete on public.competencies;create policy competencies_select on public.competencies  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy competencies_insert on public.competencies  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy competencies_update on public.competencies  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy competencies_delete on public.competencies  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- questionnairesdrop policy if exists questionnaires_select on public.questionnaires;drop policy if exists questionnaires_insert on public.questionnaires;drop policy if exists questionnaires_update on public.questionnaires;drop policy if exists questionnaires_delete on public.questionnaires;create policy questionnaires_select on public.questionnaires  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy questionnaires_insert on public.questionnaires  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy questionnaires_update on public.questionnaires  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy questionnaires_delete on public.questionnaires  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- questionsdrop policy if exists questions_select on public.questions;drop policy if exists questions_insert on public.questions;drop policy if exists questions_update on public.questions;drop policy if exists questions_delete on public.questions;create policy questions_select on public.questions  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy questions_insert on public.questions  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy questions_update on public.questions  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy questions_delete on public.questions  for delete to authenticated  using (tenant_id = app.current_tenant_id() and app.is_owner());-- questionnaire_questions (deriva do questionnaire pai)drop policy if exists qq_select on public.questionnaire_questions;drop policy if exists qq_insert on public.questionnaire_questions;drop policy if exists qq_update on public.questionnaire_questions;drop policy if exists qq_delete on public.questionnaire_questions;create policy qq_select on public.questionnaire_questions  for select to authenticated  using (    exists (      select 1 from public.questionnaires q      where q.id = questionnaire_questions.questionnaire_id        and q.tenant_id = app.current_tenant_id()        and app.is_admin_or_owner()    )  );create policy qq_insert on public.questionnaire_questions  for insert to authenticated  with check (    exists (      select 1 from public.questionnaires q      where q.id = questionnaire_questions.questionnaire_id        and q.tenant_id = app.current_tenant_id()        and app.is_admin_or_owner()    )  );create policy qq_update on public.questionnaire_questions  for update to authenticated  using (    exists (      select 1 from public.questionnaires q      where q.id = questionnaire_questions.questionnaire_id        and q.tenant_id = app.current_tenant_id()        and app.is_admin_or_owner()    )  );create policy qq_delete on public.questionnaire_questions  for delete to authenticated  using (    exists (      select 1 from public.questionnaires q      where q.id = questionnaire_questions.questionnaire_id        and q.tenant_id = app.current_tenant_id()        and app.is_owner()    )  );-- ============ CYCLES ============alter table public.cycles enable row level security;drop policy if exists cycles_select on public.cycles;drop policy if exists cycles_insert on public.cycles;drop policy if exists cycles_update on public.cycles;create policy cycles_select on public.cycles  for select to authenticated  using (    tenant_id = app.current_tenant_id()    and app.is_active_member()    and (      app.is_admin_or_owner()      or app.manager_sees_cycle(id)      or exists (        select 1 from public.cycle_participants cp        where cp.cycle_id = cycles.id          and cp.person_id = app.person_id_for_user()      )    )  );create policy cycles_insert on public.cycles  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy cycles_update on public.cycles  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());-- DELETE: bloqueado intencionalmente (usar status='archived').-- ============ CYCLE_PARTICIPANTS ============alter table public.cycle_participants enable row level security;drop policy if exists cp_select on public.cycle_participants;drop policy if exists cp_insert on public.cycle_participants;drop policy if exists cp_update on public.cycle_participants;drop policy if exists cp_delete on public.cycle_participants;create policy cp_select on public.cycle_participants  for select to authenticated  using (    tenant_id = app.current_tenant_id()    and app.is_active_member()    and (      app.is_admin_or_owner()      or person_id = app.person_id_for_user()      or app.manages_person(person_id)    )  );create policy cp_insert on public.cycle_participants  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy cp_update on public.cycle_participants  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy cp_delete on public.cycle_participants  for delete to authenticated  using (    tenant_id = app.current_tenant_id()    and app.is_admin_or_owner()    and exists (      select 1 from public.cycles c      where c.id = cycle_participants.cycle_id and c.status = 'draft'    )  );-- ============ ASSIGNMENTS ============-- SELECT direto está REVOGADO para authenticated (ver 0014).-- Leitura passa por views public.assignments_admin / public.assignments_safe.-- INSERT/UPDATE administrativos via base, gateados por RLS.alter table public.assignments enable row level security;drop policy if exists assignments_insert on public.assignments;drop policy if exists assignments_update on public.assignments;create policy assignments_insert on public.assignments  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy assignments_update on public.assignments  for update to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner())  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());-- DELETE bloqueado (cancelar via status).-- ============ RESPONSES ============-- SELECT/INSERT/UPDATE/DELETE para authenticated REVOGADOS em 0014.-- Tudo via service_role + RPC submit_response.alter table public.responses enable row level security;-- Sem policies = nenhum acesso por authenticated.-- ============ COMMENTS ============-- SELECT/INSERT/UPDATE/DELETE para authenticated REVOGADOS em 0014.-- Leitura via comments_published; auditoria forense via RPC.alter table public.comments enable row level security;-- Sem policies = nenhum acesso por authenticated.-- ============ SCORE_SNAPSHOTS ============alter table public.score_snapshots enable row level security;drop policy if exists ss_select on public.score_snapshots;create policy ss_select on public.score_snapshots  for select to authenticated  using (    tenant_id = app.current_tenant_id()    and visibility_status <> 'hidden'    and (      app.is_admin_or_owner()      or app.manages_person(          (select cp.person_id           from public.cycle_participants cp           where cp.id = score_snapshots.cycle_participant_id)        )      or (        (select cp.person_id         from public.cycle_participants cp         where cp.id = score_snapshots.cycle_participant_id)        = app.person_id_for_user()        and app.report_released(cycle_id)      )    )  );-- INSERT/UPDATE/DELETE: só service_role.-- ============ PARTICIPANT_RESULT_PROFILES ============alter table public.participant_result_profiles enable row level security;drop policy if exists prp_select on public.participant_result_profiles;create policy prp_select on public.participant_result_profiles  for select to authenticated  using (    tenant_id = app.current_tenant_id()    and (      app.is_admin_or_owner()      or app.manages_person(          (select cp.person_id           from public.cycle_participants cp           where cp.id = participant_result_profiles.cycle_participant_id)        )      or (        (select cp.person_id         from public.cycle_participants cp         where cp.id = participant_result_profiles.cycle_participant_id)        = app.person_id_for_user()        and app.report_released(cycle_id)      )    )  );-- INSERT/UPDATE/DELETE: só service_role.-- ============ INTEGRATION_EXPORTS ============alter table public.integration_exports enable row level security;drop policy if exists ie_select on public.integration_exports;drop policy if exists ie_insert on public.integration_exports;create policy ie_select on public.integration_exports  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());create policy ie_insert on public.integration_exports  for insert to authenticated  with check (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());-- UPDATE/DELETE: bloqueados (logs de export são imutáveis).-- ============ AUDIT_LOG ============alter table public.audit_log enable row level security;drop policy if exists audit_select on public.audit_log;create policy audit_select on public.audit_log  for select to authenticated  using (tenant_id = app.current_tenant_id() and app.is_admin_or_owner());-- INSERT/UPDATE/DELETE: só service_role / triggers.